def reachable_toll_sum(spec: dict) -> int:
    """Sum the toll on every road leaving any junction reachable from start."""
    adj = {}
    for s, t, w in spec["edges"]:
        adj.setdefault(s, []).append((t, w))
    seen = set()
    stack = [spec["start"]]
    total = 0
    while stack:
        n = stack.pop()
        if n in seen:
            continue
        seen.add(n)
        for t, w in adj.get(n, []):
            total += w
            stack.append(t)
    return total

