def heaviest_road_name(spec: dict) -> str:
    """Name of the longest road leaving any junction reachable from start."""
    adj = {}
    for s, t, nm, w in spec["edges"]:
        adj.setdefault(s, []).append((t, nm, w))
    seen = set()
    stack = [spec["start"]]
    best_w = -1
    best_name = ""
    while stack:
        n = stack.pop()
        if n in seen:
            continue
        seen.add(n)
        for t, nm, w in adj.get(n, []):
            if w > best_w:
                best_w = w
                best_name = nm
            stack.append(t)
    return best_name

