def discounted_total(spec: dict) -> int:
    """Total fare along the chain, half price (rounded down) on promo rides."""
    total = 0
    for fare, promo in zip(spec["fares"], spec["promos"]):
        if promo:
            total += fare // 2
        else:
            total += fare
    return total

