def light_load_reach(spec: dict) -> int:
    """Count depots reachable from start using only lanes within the load cap."""
    adj = {}
    for s, t, w in spec["edges"]:
        adj.setdefault(s, []).append((t, w))
    seen = set()
    stack = [spec["start"]]
    while stack:
        n = stack.pop()
        if n in seen:
            continue
        seen.add(n)
        for t, w in adj.get(n, []):
            if w <= spec["cap"]:
                stack.append(t)
    return len(seen)

