def busiest_kind(spec: dict) -> str:
    """Kind of road with the largest total distance among reachable roads (ties alphabetical)."""
    adj = {}
    for s, t, k, w in spec["edges"]:
        adj.setdefault(s, []).append((t, k, w))
    seen = set()
    stack = [spec["start"]]
    totals = {}
    while stack:
        n = stack.pop()
        if n in seen:
            continue
        seen.add(n)
        for t, k, w in adj.get(n, []):
            totals[k] = totals.get(k, 0) + w
            stack.append(t)
    best = ""
    for k in sorted(totals):
        if best == "" or totals[k] > totals[best]:
            best = k
    return best

