def within_fuel_count(spec: dict) -> int:
    """Count camps in the trail tree whose total distance from start fits the fuel."""
    adj = {}
    for s, t, w in spec["edges"]:
        adj.setdefault(s, []).append((t, w))
    stack = [(spec["start"], 0)]
    count = 0
    while stack:
        n, d = stack.pop()
        if d <= spec["fuel"]:
            count += 1
        for t, w in adj.get(n, []):
            stack.append((t, d + w))
    return count

